import React, { useEffect, useState, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import axios from 'axios';

const DoctorDashboard = () => {
  const { user } = useContext(AuthContext);
  const [todaysAppointments, setTodaysAppointments] = useState([]);
  const [appointmentHistory, setAppointmentHistory] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editProfile, setEditProfile] = useState(false);
  const [profile, setProfile] = useState({
    name: '',
    specialization: '',
    bio: ''
  });
  const [newAvailabilityDate, setNewAvailabilityDate] = useState('');
  const [newAvailabilityTime, setNewAvailabilityTime] = useState('');

  // Fetch all dashboard data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [apptRes, histRes, availRes, patRes, profileRes] = await Promise.all([
          axios.get('/api/doctor/today-appointments'),
          axios.get('/api/doctor/appointment-history'),
          axios.get('/api/doctor/availability'),
          axios.get('/api/doctor/patients'),
          axios.get('/api/auth/me')
        ]);

        setTodaysAppointments(apptRes.data);
        setAppointmentHistory(histRes.data);
        setAvailability(availRes.data);
        setPatients(patRes.data);
        setProfile(profileRes.data);
      } catch (err) {
        console.error('Error loading doctor dashboard:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  // Access control
  if (!user || user.role !== 'Doctor') {
    return (
        <div className="flex items-center justify-center h-screen text-xl text-red-600">
          Access Denied: Doctors Only
        </div>
    );
  }

  // Add new availability
  const handleAddAvailability = async () => {
    if (!newAvailabilityDate || !newAvailabilityTime) {
      return alert('Please provide both date and time');
    }

    try {
      const response = await axios.post('/api/doctor/availability', {
        date: newAvailabilityDate,
        timeSlot: newAvailabilityTime,
      });

      setAvailability((prev) => [...prev, response.data]);
      setNewAvailabilityDate('');
      setNewAvailabilityTime('');
    } catch (err) {
      alert('Error adding availability');
    }
  };

  // Update appointment status
  const handleStatusChange = async (id, newStatus) => {
    try {
      await axios.put(`/api/bookings/${id}/status`, {
        status: newStatus,
      });

      setTodaysAppointments((prev) =>
          prev.map((appt) =>
              appt._id === id ? { ...appt, status: newStatus } : appt
          )
      );
    } catch (err) {
      alert('Failed to update status');
    }
  };

  // Profile update handler
  const handleProfileChange = (e) => {
    setProfile({ ...profile, [e.target.name]: e.target.value });
  };

  const handleProfileSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.put('/api/auth/profile', profile);
      setEditProfile(false);
      alert('Profile updated successfully');
    } catch (err) {
      alert('Error updating profile');
    }
  };

  if (loading) {
    return (
        <div className="flex items-center justify-center h-screen text-lg">
          Loading Doctor Dashboard...
        </div>
    );
  }

  return (
      <div className="min-h-screen p-6 max-w-7xl mx-auto bg-gray-100 text-gray-900">
        <h1 className="text-3xl font-bold text-center mb-6 text-blue-700">Doctor Dashboard</h1>

        <div className="grid gap-6 md:grid-cols-2">
          {/* Today's Appointments */}
          <section className="bg-white p-5 rounded shadow">
            <h2 className="text-xl font-semibold mb-4">Today's Appointments</h2>
            {todaysAppointments.length === 0 ? (
                <p>No appointments today.</p>
            ) : (
                <table className="w-full text-sm border">
                  <thead className="bg-blue-100">
                  <tr>
                    <th className="px-2 py-1 text-left">Patient</th>
                    <th className="px-2 py-1 text-left">Time</th>
                    <th className="px-2 py-1 text-left">Status</th>
                  </tr>
                  </thead>
                  <tbody>
                  {todaysAppointments.map((appt) => (
                      <tr key={appt._id} className="border-t">
                        <td className="px-2 py-1">{appt.patientName}</td>
                        <td className="px-2 py-1">{appt.time}</td>
                        <td className="px-2 py-1">
                          <select
                              value={appt.status}
                              onChange={(e) => handleStatusChange(appt._id, e.target.value)}
                              className="px-2 py-1 border rounded"
                          >
                            <option value="Pending">Pending</option>
                            <option value="Confirmed">Confirmed</option>
                            <option value="Cancelled">Cancelled</option>
                            <option value="Completed">Completed</option>
                          </select>
                        </td>
                      </tr>
                  ))}
                  </tbody>
                </table>
            )}
          </section>

          {/* Manage Availability */}
          <section className="bg-white p-5 rounded shadow">
            <h2 className="text-xl font-semibold mb-4">Manage Availability</h2>
            <div className="flex flex-col gap-2 mb-4">
              <input
                  type="date"
                  value={newAvailabilityDate}
                  onChange={(e) => setNewAvailabilityDate(e.target.value)}
                  className="border rounded px-2 py-1"
              />
              <input
                  type="time"
                  value={newAvailabilityTime}
                  onChange={(e) => setNewAvailabilityTime(e.target.value)}
                  className="border rounded px-2 py-1"
              />
              <button
                  onClick={handleAddAvailability}
                  className="bg-blue-500 text-white px-3 py-1 rounded hover:bg-blue-600"
              >
                Add Availability
              </button>
            </div>
            <ul className="list-disc ml-5">
              {availability.map((slot) => (
                  <li key={slot._id}>
                    {slot.date}: {slot.timeSlot}
                  </li>
              ))}
            </ul>
          </section>

          {/* Patient List */}
          <section className="bg-white p-5 rounded shadow">
            <h2 className="text-xl font-semibold mb-4">Patients</h2>
            {patients.length === 0 ? (
                <p>No patients found.</p>
            ) : (
                <ul className="space-y-2">
                  {patients.map((p) => (
                      <li key={p._id} className="border p-2 rounded bg-gray-50">
                        {p.name}
                        <br />
                        <span className="text-sm text-gray-500">Last Visit: {p.lastVisit}</span>
                      </li>
                  ))}
                </ul>
            )}
          </section>

          {/* Appointment History */}
          <section className="bg-white p-5 rounded shadow">
            <h2 className="text-xl font-semibold mb-4">Appointment History</h2>
            {appointmentHistory.length === 0 ? (
                <p>No past appointments.</p>
            ) : (
                <table className="w-full text-sm border">
                  <thead className="bg-blue-100">
                  <tr>
                    <th className="px-2 py-1 text-left">Patient</th>
                    <th className="px-2 py-1 text-left">Date</th>
                    <th className="px-2 py-1 text-left">Status</th>
                  </tr>
                  </thead>
                  <tbody>
                  {appointmentHistory.map((appt) => (
                      <tr key={appt._id} className="border-t">
                        <td className="px-2 py-1">{appt.patientName}</td>
                        <td className="px-2 py-1">{appt.date}</td>
                        <td className="px-2 py-1">{appt.status}</td>
                      </tr>
                  ))}
                  </tbody>
                </table>
            )}
          </section>
        </div>

        {/* Profile Section */}
        <section className="mt-8 bg-white rounded shadow p-5 max-w-3xl mx-auto">
          <h2 className="text-xl font-semibold mb-4">Profile Settings</h2>
          {editProfile ? (
              <form onSubmit={handleProfileSubmit} className="space-y-4">
                <input
                    name="name"
                    value={profile.name}
                    onChange={handleProfileChange}
                    className="border rounded w-full p-2"
                    placeholder="Name"
                />
                <input
                    name="specialization"
                    value={profile.specialization}
                    onChange={handleProfileChange}
                    className="border rounded w-full p-2"
                    placeholder="Specialization"
                />
                <textarea
                    name="bio"
                    value={profile.bio}
                    onChange={handleProfileChange}
                    className="border rounded w-full p-2"
                    placeholder="Bio"
                />
                <div className="flex gap-3">
                  <button type="submit" className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600">
                    Save
                  </button>
                  <button
                      type="button"
                      onClick={() => setEditProfile(false)}
                      className="bg-gray-400 text-white px-4 py-2 rounded hover:bg-gray-500"
                  >
                    Cancel
                  </button>
                </div>
              </form>
          ) : (
              <div className="space-y-2">
                <p><strong>Name:</strong> {profile.name}</p>
                <p><strong>Specialization:</strong> {profile.specialization}</p>
                <p><strong>Bio:</strong> {profile.bio}</p>
                <button
                    onClick={() => setEditProfile(true)}
                    className="bg-blue-500 text-white px-3 py-1 mt-3 rounded hover:bg-blue-600"
                >
                  Edit Profile
                </button>
              </div>
          )}
        </section>
      </div>
  );
};

export default DoctorDashboard;
